# Shape module - imports from utils for calculations
from utils import PI, square, double

class Rectangle:
    width: float
    height: float

    def __init__(self, w: float, h: float):
        self.width = w
        self.height = h

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return double(self.width) + double(self.height)

class Circle:
    radius: float

    def __init__(self, r: float):
        self.radius = r

    def area(self) -> float:
        return PI * square(self.radius)

    def circumference(self) -> float:
        return PI * double(self.radius)
